--
-- Name: match_documents(public.vector, integer, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.match_documents(query_embedding public.vector, match_count integer DEFAULT 5, filter jsonb DEFAULT '{}'::jsonb) RETURNS TABLE(id bigint, content text, metadata jsonb, similarity double precision)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    d.id,
    d.content,
    d.metadata,
    1 - (d.embedding <=> query_embedding) AS similarity
  FROM documents d
  WHERE
    -- Se não veio filtro, retorna tudo. Se veio tenant_id, filtra.
    (filter = '{}' OR (d.metadata->>'tenant_id') = (filter->>'tenant_id'))
  ORDER BY d.embedding <=> query_embedding
  LIMIT match_count;
END;
$$;


ALTER FUNCTION public.match_documents(query_embedding public.vector, match_count integer, filter jsonb) OWNER TO postgres;

--
-- Name: rename_tenant(text, text); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.rename_tenant(IN old_slug text, IN new_slug text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    all_tables TEXT[] := ARRAY['admin_supabase_credentials','admin_users','app_promotion_configs','app_settings','appearance_configs','audit_trail','bank_accounts','better_stack_config','bigdatacorp_config','boletos','cache_config','categories','chat_attachments','chat_messages','chat_threads','chats','clientes_completos','cloudflare_config','commission_config','commission_splits','companies','company_settings','completion_pages','compliance_audit_log','compliance_users','config_frete','config_split','contract_configs','contracts','cotacoes_frete','cpf_compliance_results','customers','dados_cliente','datacorp_checks','debug_logs','device_tokens','envios','equipe_empresa','etiquetas_envio','evolution_api_config','evolution_connections','faixa_frete','files','followup_status','form_submissions','form_submissions_compliance_tracking','form_templates','form_tenant_mapping','forms','formulario_cliente','formulario_envios','formulario_personalizado','formulario_sessoes','formularios','gamification_activities','gamification_badges','gamification_challenges','gamification_config','gamification_leagues','gamification_levels','gamification_rewards','global_appearance_settings','google_calendar_config','google_calendar_webhooks','google_tokens','gravacoes','historico_reunioes','hms_100ms_config','horarios_disponiveis','imagens_9fotos','imagens_gratis','integration_queue','lead_historico','leads','meeting_bookings','meeting_confirmation_pages','meeting_templates','meeting_tenant_config','meeting_tenant_mapping','meeting_tenants','meeting_types','meeting_usuarios','message_categories','monitoring_config','n8n_chat_histories','n8n_chat_histories_gerente','n8n_config','notificacoes_enviadas','notification_history','notification_settings','optimizer_config','order_items','orders','platform_settings','print_queue','product_requests','products','progress_tracker_configs','rastreamento_eventos','redis_config','reseller_alerts','reseller_badges','reseller_challenges','reseller_profiles','reseller_rewards','reseller_stores','reseller_supabase_configs','reseller_welcome_configs','resellers','resend_config','reuniao_prospecto','reunioes','reunioes_equipe','revendedoras','revendedoras_ativas','sales_with_split','sentry_config','service_prices','setores','settings','signature_logs','store_banners','store_benefits','store_campaigns','store_categories','store_collections','store_mosaics','store_pages','store_product_images','store_product_variants','store_products','store_reseller_profiles','store_sections','store_settings','store_themes','store_videos','supabase_config','supabase_master_config','suppliers','tabela_frete','total_express_config','transcricoes','transportadoras','users','usuario_preferencias','vendas_revendedora','verification_configs','wallet_transactions','wallets','whatsapp_labels','whatsapp_qr_codes','withdrawals','workspace_boards','workspace_databases','workspace_pages','workspace_public_mapping'];
    t TEXT;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM public.tenants_registry WHERE slug = old_slug) THEN
    RAISE EXCEPTION 'Tenant origem nao encontrado: %', old_slug;
  END IF;
  IF EXISTS (SELECT 1 FROM public.tenants_registry WHERE slug = new_slug) THEN
    RAISE EXCEPTION 'Tenant destino ja existe: %', new_slug;
  END IF;

  -- Atualizar slug na tenants_registry
  -- ON UPDATE CASCADE cuida das 3 FKs automaticamente
  UPDATE public.tenants_registry SET slug = new_slug WHERE slug = old_slug;

  -- Atualizar tenant_id em todas as tabelas
  FOREACH t IN ARRAY all_tables LOOP
    IF EXISTS (SELECT FROM information_schema.tables WHERE table_schema='public' AND table_name=t) THEN
      IF EXISTS (SELECT FROM information_schema.columns WHERE table_schema='public' AND table_name=t AND column_name='tenant_id') THEN
        EXECUTE format('UPDATE public.%I SET tenant_id = %L WHERE tenant_id = %L', t, new_slug, old_slug);
      END IF;
    END IF;
  END LOOP;

  -- Sincronizar Evolution API instance
  IF EXISTS (SELECT FROM information_schema.columns WHERE table_schema='public' AND table_name='evolution_api_config' AND column_name='instance') THEN
    UPDATE public.evolution_api_config SET instance = new_slug WHERE instance = old_slug OR tenant_id = new_slug;
  END IF;

  RAISE NOTICE 'Tenant renomeado com sucesso: % -> %', old_slug, new_slug;
END;
$$;


ALTER PROCEDURE public.rename_tenant(IN old_slug text, IN new_slug text) OWNER TO postgres;

