--
-- Name: sistema_data_atual; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.sistema_data_atual AS
 SELECT 1 AS id,
    CURRENT_DATE AS data_atual,
    CURRENT_TIME AS hora_atual,
    (EXTRACT(year FROM CURRENT_DATE))::integer AS ano_atual,
    (EXTRACT(month FROM CURRENT_DATE))::integer AS mes_atual,
    (EXTRACT(day FROM CURRENT_DATE))::integer AS dia_atual,
    to_char((CURRENT_DATE)::timestamp with time zone, 'DD/MM/YYYY'::text) AS data_formatada,
    to_char((CURRENT_DATE)::timestamp with time zone, 'YYYY-MM-DD'::text) AS data_iso,
    now() AS updated_at;


